head.script:
//전역변수  
scwin.userInfo              = $c.data.getMemInfo();
scwin.strCurDate            = WebSquare.date.getCurrentServerDate();
scwin.curDate               = scwin.strCurDate.substring( 0 , 6 )



//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {
    const codeOptions = [
        { grpCd : "ZZ205", compID : "lc_homeClsCd", opt : {'range': '1,EQ'}  },
    ];
    $c.data.setCommonCode(codeOptions);
    lc_homeClsCd.setSelectedIndex(-1);
};

scwin.onUdcCompleted = function() {
	ed_wrkStYm.setValue(scwin.curDate);
    ed_wrkEndYm.setValue(scwin.curDate);


    lc_homeClsCd.setValue(scwin.userInfo.eqHomeClsCd)  // 정비소속구분코드

    scwin.f_sbm_ds_lux_wrkPlCd();

    ed_wrkStYm.focus();
};

scwin.ondataload = function(e) {
    scwin.f_sbm_ds_lux_wrkPlCd();
}

//-------------------------------------------------------------------------
// ds_lux_wrkPlCd submission
//-------------------------------------------------------------------------
scwin.f_sbm_ds_lux_wrkPlCd = function() {
    sbm_ds_lux_wrkPlCd.action = "/cm.zz.RetrieveComboCMD.do?sysCd=PsCommonEBC&queryId=retriveWrkplList&param1="+lc_homeClsCd.getValue();
    $c.sbm.execute(sbm_ds_lux_wrkPlCd);
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    if( ! await $c.gus.cfValidate([ed_wrkStYm, ed_wrkEndYm, lc_homeClsCd, lc_wrkPlCd, ed_partCd])) return;

    if (ed_wrkStYm.getValue()> ed_wrkEndYm.getValue()) {
        $c.win.alert( MSG_CM_ERR_039 ); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
        ed_wrkStDt.focus();
        return;
    }

    // dma_fix_work_re.setUseChangeInfo(false); // 조회조건

    let strPath = "/ps.eq.adjmmgnt.fixrslts.RetrieveVehiclesEachPartsUsePresentConditionCMD.do";
    sbm_retrieve.action = strPath;
    $c.sbm.execute(sbm_retrieve);
};

//-------------------------------------------------------------------------
// 조회 조건 지우기
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(tb_wrk, null);
    lc_wrkPlCd.setValue(scwin.userInfo.fixWrkPlCd);        // 정비작업장코드
    scwin.lc_homeClsCd_onviewchange();
};


//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = async function(disGubun, pCode, pName, pClose, pAllSearch) {
    // 선언부
    let rtnList;  //공통POP-UP -> 요청화면 
    let pWhere = "";		

    switch (disGubun)
    {
        case 1:

            // 정비사 팝업			
            rtnList = udc_eqBasicListInfo.cfCommonPopUp(scwin.udc_eqBasicListInfo_callBackFunc, ed_eqCd.getValue().trim()      
                                    ,ed_vehclNo.getValue()		  
                                    ,pClose					  
                                    ,null					  
                                    ,null					  
                                    ,null					  
                                    ,null					  
                                    ,null					  
                                    ,null					  
                                    ,null					  
                                    ,null					  
                                    ,null					  
                                    ,null					  
                                    ,pAllSearch				  
                                    ,"장비,장비코드,차량번호");

            // cfSetReturnValue(rtnList, ed_eqCd,   ed_vehclNo);
            break;			
        //사용안함
        case 2:
            // 거래처 팝업			
            rtnList = udc_fixClntList.cfCommonPopUp(scwin.udc_fixClntList_callBackFunc, pCode				         
                                    ,pName				         
                                    ,pClose				         
                                    ,null				         
                                    ,null				         
                                    ,null				         
                                    ,null				         
                                    ,null				         
                                    ,null				         
                                    ,null				         
                                    ,null					     
                                    ,null				         
                                    ,null				         
                                    ,pAllSearch				     
                                    ,"거래처,거래처코드,거래처명");

            // cfSetReturnValue(rtnList, ed_clntNo, ed_clntNm);  			
            break;


        case 3:
            // 부품 팝업			
            rtnList = udc_partInfo.cfCommonPopUp(scwin.udc_partInfo_callBackFunc, pCode				   
                                    ,pName				   
                                    ,pClose				   
                                    ,null				   
                                    ,null				   
                                    ,null				   
                                    ,"3,4,5,6,7,8,9,10"		
                                    ,null				   
                                    ,null				   
                                    ,null				   
                                    ,null				   
                                    ,null			       
                                    ,null				   
                                    ,pAllSearch				
                                    ,"부품,부품코드,부품명"); 

            // cfSetReturnValue(rtnList, ed_partCd, ed_partNm);
            break;	

            case 4:			
                // 귀속부서 팝업			
                rtnList = udc_acctDeptCdInfo.cfCommonPopUp(scwin.udc_acctDeptCdInfo_callBackFunc, ed_acctDeptCd.getValue().trim() 
                                        ,ed_acctDeptNm.getValue() 		
                                        ,pClose					   
                                        ,null					   
                                        ,null					   
                                        ,null					   
                                        ,null					   
                                        ,pWhere					   
                                        ,null					   
                                        ,null					   
                                        ,null					   
                                        ,null					   
                                        ,null					   
                                        ,"T"				       
                                        ,"귀속부서,부서코드,부서명");
                // cfSetReturnValue(rtnList, ed_acctDeptCd,   ed_acctDeptNm);
                break;

    }
}

// ======================
// 콜백 함수들
// ======================
scwin.udc_eqBasicListInfo_callBackFunc = function(rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        ed_eqCd.setValue(rtnList[0]);
        ed_vehclNo.setValue(rtnList[1]);
        ed_eqCd.options.hidVal = rtnList[0];
        ed_vehclNo.options.hidVal = rtnList[1];
    } else {
        ed_eqCd.setValue("");
        ed_vehclNo.setValue("");
        ed_eqCd.options.hidVal = "";
        ed_vehclNo.options.hidVal = "";
    }
};

scwin.udc_fixClntList_callBackFunc = function(rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        ed_clntNo.setValue(rtnList[0]);
        ed_clntNm.setValue(rtnList[1]);
        ed_clntNo.options.hidVal = rtnList[0];
        ed_clntNm.options.hidVal = rtnList[1];
    } else {
        ed_clntNo.setValue("");
        ed_clntNm.setValue("");
        ed_clntNo.options.hidVal = "";
        ed_clntNm.options.hidVal = "";
    }
};

scwin.udc_partInfo_callBackFunc = function(rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        ed_partCd.setValue(rtnList[0]);
        ed_partNm.setValue(rtnList[1]);
        ed_partCd.options.hidVal = rtnList[0];
        ed_partNm.options.hidVal = rtnList[1];
    } else {
        ed_partCd.setValue("");
        ed_partNm.setValue("");
        ed_partCd.options.hidVal = "";
        ed_partNm.options.hidVal = "";
    }
};

scwin.udc_acctDeptCdInfo_callBackFunc = function(rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        ed_acctDeptCd.setValue(rtnList[0]);
        ed_acctDeptNm.setValue(rtnList[1]);
        ed_acctDeptCd.options.hidVal = rtnList[0];
        ed_acctDeptNm.options.hidVal = rtnList[1];
    } else {
        ed_acctDeptCd.setValue("");
        ed_acctDeptNm.setValue("");
        ed_acctDeptCd.options.hidVal = "";
        ed_acctDeptNm.options.hidVal = "";
    }
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = async function(inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (! await $c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    // 짝이 되는 오브젝트의 값 제거
    // $c.gus.cfClearPairObj(pairObj);
    pairObj.setValue("");

    // 검색어 세팅
    // let pVal = $c.gus.cfGetValue(inObj);
    let pVal = inObj.getValue();

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
    else
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
};

//-------------------------------------------------------------------------
// 엑셀 출력
//-------------------------------------------------------------------------
scwin.f_Excel = async function () {	    
    let cntRow = ds_fix_fee_list.getRowCount();
    if(cntRow == 0)
        return;
    let startRowIndex = 5;
    let infoArr = [{
        rowIndex : 0,             // 첫 번째 줄
        colIndex : 0,             // 첫 번째 칸부터
        colSpan : 9,   // 그리드 전체 너비만큼 병합
        rowSpan : 1,
        text : "차량별 특정부품 사용현황",
        textAlign : "center",     //정렬
        fontSize : 12,
        drawBorder : false,        // 테두리
        color : "black",          // 글자색
        backgroundColor : "white" // 배경색
    },{
        rowIndex : 2,             // 첫 번째 줄
        colIndex : 0,             // 첫 번째 칸부터
        colSpan : 9,   // 그리드 전체 너비만큼 병합
        rowSpan : 1,
        text : "정비기간 ["+ $c.gus.cfGetFormatStr(ed_wrkStYm.getValue(), "####/##")+ " ~ " + $c.gus.cfGetFormatStr(ed_wrkEndYm.getValue(), "####/##") + "]",
        textAlign : "left",     //정렬
        fontSize : 10,
        drawBorder : false,        // 테두리
        color : "black",          // 글자색
        backgroundColor : "white" // 배경색
    },{
        rowIndex : 3,             // 첫 번째 줄
        colIndex : 0,             // 첫 번째 칸부터
        colSpan : 9,   // 그리드 전체 너비만큼 병합
        rowSpan : 1,
        text : "사업부문 ["+$c.win.getComboLabel(lc_homeClsCd)+"]",
        textAlign : "left",     //정렬
        fontSize : 10,
        drawBorder : false,        // 테두리
        color : "black",          // 글자색
        backgroundColor : "white" // 배경색
    },{
        rowIndex : 4,             // 첫 번째 줄
        colIndex : 0,             // 첫 번째 칸부터
        colSpan : 9,   // 그리드 전체 너비만큼 병합
        rowSpan : 1,
        text : "정비작업장 ["+$c.win.getComboLabel(lc_wrkPlCd)+"]",
        textAlign : "left",     //정렬
        fontSize : 10,
        drawBorder : false,        // 테두리
        color : "black",          // 글자색
        backgroundColor : "white" // 배경색
    }]

    let lowIdx = 4
    if (ed_partCd.getValue().length !== 0) {
        lowIdx = lowIdx + 1
        infoArr.push({
            rowIndex : lowIdx,             // 첫 번째 줄
            colIndex : 0,             // 첫 번째 칸부터
            colSpan : 9,   // 그리드 전체 너비만큼 병합
            rowSpan : 1,
            text : "부품 ["+ed_partCd.getValue().trim() + " - " + ed_partNm.getValue().trim()+"]",
            textAlign : "left",     //정렬
            fontSize : 10,
            drawBorder : false,        // 테두리
            color : "black",          // 글자색
            backgroundColor : "white" // 배경색
        })
        startRowIndex = startRowIndex + 1;
    }

    if (ed_eqCd.getValue().length !== 0) {
        lowIdx = lowIdx + 1
        infoArr.push({
            rowIndex : lowIdx,             // 첫 번째 줄
            colIndex : 0,             // 첫 번째 칸부터
            colSpan : 9,   // 그리드 전체 너비만큼 병합
            rowSpan : 1,
            text : "장비 ["+ed_eqCd.getValue().trim() + " - " + ed_vehclNo.getValue().trim()+"]",
            textAlign : "left",     //정렬
            fontSize : 10,
            drawBorder : false,        // 테두리
            color : "black",          // 글자색
            backgroundColor : "white" // 배경색
        })
        startRowIndex = startRowIndex + 1;
    }

    if (ed_acctDeptCd.getValue().length !== 0) {
        lowIdx = lowIdx + 1
        infoArr.push({
            rowIndex : lowIdx,             // 첫 번째 줄
            colIndex : 0,             // 첫 번째 칸부터
            colSpan : 9,   // 그리드 전체 너비만큼 병합
            rowSpan : 1,
            text : "귀속부서 ["+ed_acctDeptCd.getValue().trim() + " - " + ed_acctDeptNm.getValue().trim()+"]",
            textAlign : "left",     //정렬
            fontSize : 10,
            drawBorder : false,        // 테두리
            color : "black",          // 글자색
            backgroundColor : "white" // 배경색
        })
        startRowIndex = startRowIndex + 1;
    }

    const options = {
        fileName: "차량별 특정부품 사용현황 조회.xlsx",
        sheetName: "차량별 특정부품 사용현황 조회",
        startRowIndex : startRowIndex,       
        startColumnIndex : 0,
        type : 1,
    };

    $c.data.downloadGridViewExcel(gr_work_pl, options, infoArr);

};

